module shift_reg_16bit(
    input clk,
    input rst,
    input load,
    input sin,
    input [15:0] pdata,
    output sout,
    output [15:0] q
);

    reg [15:0] obf_shift_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_shift_reg <= 16'b0;
        end else if (load) begin
            obf_shift_reg <= pdata;
        end else begin
            obf_shift_reg <= {obf_shift_reg[14:0], sin};
        end
    end

    assign sout = obf_shift_reg[15];
    assign q = obf_shift_reg;

endmodule
